  4→
  5→import chalk from "chalk";
  6→import inquirer from "inquirer";
  7→import { ui, colors } from "../lib/cli-ui.js";
  8→import {
  9→  detectStack,
 10→  detectAllStacks,
 11→  getStackConfig,
 12→  detectPackageManager,
 13→  getPackageManagerCommands,
 14→  STACKS,
 15→} from "../lib/stacks.js";
 16→import { copyTemplates } from "../lib/templates.js";
 17→import { createManifest } from "../lib/manifest.js";
 18→import { saveConfig } from "../lib/config.js";
 19→import { createDefaultSettings } from "../lib/settings.js";
 20→import { detectAndSaveConventions } from "../lib/conventions-detector.js";
 21→import { fileExists, ensureDir, readFile, writeFile } from "../lib/fs.js";
 22→import { generateAgentsMd, writeAgentsMd } from "../lib/agents-md.js";
 23→import {
 24→  commandExists,
 25→  isGhAuthenticated,
 26→  getInstallHint,
 27→} from "../lib/system.js";
 28→import {
 29→  shouldUseInteractiveMode,
 30→  getNonInteractiveReason,
 31→} from "../lib/tty.js";
 32→import {
 33→  checkAllDependencies,
 34→  displayDependencyStatus,
 35→  runSetupWizard,
 36→  shouldRunSetupWizard,
 37→} from "../lib/wizard.js";
 38→import { saveStackConfig, type StackConfigFile } from "../lib/stack-config.js";
 39→
 40→/**
 41→ * Check prerequisites and display warnings
 42→ */
 43→function checkPrerequisites(): { warnings: string[]; suggestions: string[] } {
 44→  const warnings: string[] = [];
 45→  const suggestions: string[] = [];
 46→
 47→  // Check for gh CLI
 48→  if (!commandExists("gh")) {
 49→    warnings.push(
 50→      "GitHub CLI (gh) is not installed. Required for issue workflows.",
 51→    );
 52→    suggestions.push(`Install: ${getInstallHint("gh")}`);
 53→  } else if (!isGhAuthenticated()) {
 54→    warnings.push("GitHub CLI is not authenticated.");
 55→    suggestions.push("Run: gh auth login");
 56→  }
 57→
 58→  // Check for jq (optional)
 59→  if (!commandExists("jq")) {
 60→    suggestions.push(
 61→      `Optional: Install jq for faster JSON parsing (${getInstallHint("jq")})`,
 62→    );
 63→  }
 64→
 65→  return { warnings, suggestions };
 66→}
 67→
 68→interface InitOptions {
 69→  stack?: string;
 70→  yes?: boolean;
 71→  force?: boolean;
 72→  interactive?: boolean;
 73→  skipSetup?: boolean;
 74→  noSymlinks?: boolean;
 75→  agentsMd?: boolean;
 76→  mcp?: boolean;
 77→}
 78→
 79→/**
 80→ * Entries to add to .gitignore
 81→ */
 82→const GITIGNORE_ENTRIES = [
 83→  "",
 84→  "# Sequant runtime data (logs, settings)",
 85→  ".sequant/",
 86→];
 87→
 88→/**
 89→ * Update .gitignore with Sequant entries
 90→ */
 91→async function updateGitignore(): Promise<boolean> {
 92→  const gitignorePath = ".gitignore";
 93→  let content = "";
 94→
 95→  if (await fileExists(gitignorePath)) {
 96→    content = await readFile(gitignorePath);
 97→
 98→    // Check if already has .sequant/
 99→    if (content.includes(".sequant/")) {
100→      return false; // Already configured
101→    }
102→  }
103→
104→  // Append entries
105→  const newContent =
106→    content.trimEnd() + "\n" + GITIGNORE_ENTRIES.join("\n") + "\n";
107→  await writeFile(gitignorePath, newContent);
108→  return true;
109→}
110→
111→/**
112→ * Log a default value being used in non-interactive mode
113→ */
114→function logDefault(label: string, value: string): void {
115→  console.log(chalk.blue(`📦 ${label}: ${value} (default)`));
116→}
117→
118→export async function initCommand(options: InitOptions): Promise<void> {
119→  // Show banner
120→  console.log(ui.banner());
121→  console.log(colors.success("\nInitializing Sequant...\n"));
122→
123→  // Determine if we should use interactive mode
124→  const useInteractive = shouldUseInteractiveMode(options.interactive);
125→  const skipPrompts = options.yes || !useInteractive;
126→
127→  // Show non-interactive mode message if applicable
128→  if (!useInteractive && !options.yes) {
129→    const reason = getNonInteractiveReason();
130→    console.log(
131→      chalk.yellow(
132→        `⚡ Non-interactive mode detected${reason ? ` (${reason})` : ""}`,
133→      ),
134→    );
135→    console.log(
136→      chalk.gray("   Using defaults. Use --interactive to force prompts.\n"),
137→    );
138→  }
139→
140→  // Check dependencies and run setup wizard if needed
141→  const depCheckResult = checkAllDependencies();
142→  let wizardRemainingIssues: string[] = [];
143→
144→  if (
145→    shouldRunSetupWizard({ skipSetup: options.skipSetup, yes: options.yes })
146→  ) {
147→    // Display dependency status
148→    displayDependencyStatus(depCheckResult);
149→
150→    // Run wizard if there are missing required dependencies
151→    if (depCheckResult.hasMissing) {
152→      const wizardResult = await runSetupWizard(depCheckResult, {
153→        skipPrompts,
154→      });
155→      wizardRemainingIssues = wizardResult.remainingIssues;
156→    }
157→  } else if (options.skipSetup) {
158→    // User explicitly skipped - show brief status
159→    console.log(
160→      chalk.gray("Skipping dependency setup wizard (--skip-setup)\n"),
161→    );
162→  }
163→
164→  // Fall back to legacy warning system for any remaining issues
165→  const { warnings, suggestions } = checkPrerequisites();
166→
167→  // Only show warnings if wizard didn't already handle them or if there are remaining issues
168→  if (
169→    wizardRemainingIssues.length > 0 ||
170→    (options.skipSetup && warnings.length > 0)
171→  ) {
172→    if (wizardRemainingIssues.length > 0) {
173→      console.log(chalk.yellow("⚠️  Remaining setup issues:\n"));
174→      for (const issue of wizardRemainingIssues) {
175→        console.log(chalk.yellow(`   • ${issue}`));
176→      }
177→      console.log();
178→    } else if (warnings.length > 0) {
179→      console.log(chalk.yellow("⚠️  Prerequisites:\n"));
180→      for (const warning of warnings) {
181→        console.log(chalk.yellow(`   • ${warning}`));
182→      }
183→      for (const suggestion of suggestions.filter(
184→        (s) => !s.startsWith("Optional"),
185→      )) {
186→        console.log(chalk.gray(`     ${suggestion}`));
187→      }
188→      console.log();
189→    }
190→  }
191→
192→  // Check if already initialized
193→  const configExists = await fileExists(".claude/settings.json");
194→  if (configExists && !options.force) {
195→    console.log(
196→      chalk.yellow(
197→        "⚠️  Sequant appears to be already initialized (.claude/settings.json exists)",
198→      ),
199→    );
200→    console.log(chalk.gray("   Use --force to reinitialize\n"));
201→
202→    if (!skipPrompts) {
203→      const { proceed } = await inquirer.prompt([
204→        {
205→          type: "confirm",
206→          name: "proceed",
207→          message: "Continue anyway?",
208→          default: false,
209→        },
210→      ]);
211→      if (!proceed) {
212→        console.log(chalk.gray("Aborted."));
213→        return;
214→      }
215→    }
216→  }
217→
218→  // Detect or prompt for stack
219→  let stack = options.stack;
220→  let additionalStacks: string[] = [];
221→
222→  if (!stack) {
223→    // Check for multi-stack project in interactive mode
224→    const allDetectedStacks = !skipPrompts ? await detectAllStacks() : [];
225→
226→    if (allDetectedStacks.length > 1 && !skipPrompts) {
227→      // Multi-stack project detected - show checkbox selection
228→      console.log(
229→        chalk.blue(
230→          `\n🔍 Detected ${allDetectedStacks.length} stacks in this project:`,
231→        ),
232→      );
233→      for (const ds of allDetectedStacks) {
234→        const location = ds.path ? ` (${ds.path}/)` : " (root)";
235→        console.log(
236→          chalk.gray(
237→            `   • ${STACKS[ds.stack]?.displayName || ds.stack}${location}`,
238→          ),
239→        );
240→      }
241→      console.log();
242→
243→      // Multi-stack selection prompt
244→      const { selectedStacks } = await inquirer.prompt([
245→        {
246→          type: "checkbox",
247→          name: "selectedStacks",
248→          message: "Select stacks to include in your constitution:",
249→          choices: allDetectedStacks.map((ds) => ({
250→            name: `${STACKS[ds.stack]?.displayName || ds.stack}${ds.path ? ` (${ds.path}/)` : " (root)"}`,
251→            value: ds.stack,
252→            checked: true, // Pre-select all detected stacks
253→          })),
254→          validate: (answer: string[]) => {
255→            if (answer.length < 1) {
256→              return "You must select at least one stack.";
257→            }
258→            return true;
259→          },
260→        },
261→      ]);
262→
263→      // First selected stack is the primary
264→      if (selectedStacks.length > 0) {
265→        stack = selectedStacks[0];
266→        additionalStacks = selectedStacks.slice(1);
267→      }
268→
269→      // Confirm or change primary stack if multiple selected
270→      if (selectedStacks.length > 1) {
271→        const { primaryStack } = await inquirer.prompt([
272→          {
273→            type: "list",
274→            name: "primaryStack",
275→            message:
276→              "Which stack should be the primary? (determines dev URL and commands)",
277→            choices: selectedStacks.map((s: string) => ({
278→              name: STACKS[s]?.displayName || s,
279→              value: s,
280→            })),
281→          },
282→        ]);
283→        stack = primaryStack;
284→        additionalStacks = selectedStacks.filter(
285→          (s: string) => s !== primaryStack,
286→        );
287→      }
288→    } else {
289→      // Single stack detection (original behavior)
290→      const detected = await detectStack();
291→      if (detected && skipPrompts) {
292→        stack = detected;
293→        logDefault("Detected stack", stack);
294→      } else if (detected && !skipPrompts) {
295→        const { confirmedStack } = await inquirer.prompt([
296→          {
297→            type: "list",
298→            name: "confirmedStack",
299→            message: `Detected ${detected} project. Is this correct?`,
300→            choices: [
301→              { name: `Yes, use ${detected}`, value: detected },
302→              { name: "No, let me choose", value: null },
303→            ],
304→          },
305→        ]);
306→        stack = confirmedStack;
307→      }
308→
309→      if (!stack && skipPrompts) {
310→        // No detection and skipping prompts: use generic as default
311→        stack = "generic";
312→        logDefault("Using stack", stack);
313→      } else if (!stack) {
314→        const { selectedStack } = await inquirer.prompt([
315→          {
316→            type: "list",
317→            name: "selectedStack",
318→            message: "Select your project stack:",
319→            choices: [
320→              { name: "Next.js / React", value: "nextjs" },
321→              { name: "Astro", value: "astro" },
322→              { name: "SvelteKit", value: "sveltekit" },
323→              { name: "Remix", value: "remix" },
324→              { name: "Nuxt", value: "nuxt" },
325→              { name: "Rust", value: "rust" },
326→              { name: "Python", value: "python" },
327→              { name: "Go", value: "go" },
